import { useState, useCallback, useEffect } from 'react';
import { GoogleMap, useJsApiLoader, Marker, InfoWindow } from '@react-google-maps/api';

const CENTER = { lat: 34.0522, lng: -118.2437 };

const MOCK_LOCATIONS = [
  { id: 1, name: 'Folding Tables', quantity: 120, lat: 34.0522, lng: -118.2437 },
  { id: 2, name: 'Stadium Seats', quantity: 350, lat: 34.0736, lng: -118.2398 },
  { id: 3, name: 'Lighting Equipment', quantity: 80, lat: 34.0195, lng: -118.4912 },
  { id: 4, name: 'Tents & Canopies', quantity: 45, lat: 34.0425, lng: -118.2668 },
  { id: 5, name: 'Fencing Panels', quantity: 200, lat: 33.9425, lng: -118.4081 },
  { id: 6, name: 'Audio Equipment', quantity: 30, lat: 34.1478, lng: -118.1445 },
];

const MAP_STYLE = { width: '100%', height: 'calc(100vh - 56px)' };

export default function Map() {
  const [selected, setSelected] = useState(null);

  useEffect(() => {
    const key = process.env.REACT_APP_GOOGLE_MAPS_API_KEY;
    console.log('[Map] REACT_APP_GOOGLE_MAPS_API_KEY:', key ? `${key.slice(0, 8)}…` : 'UNDEFINED');
  }, []);

  const { isLoaded, loadError } = useJsApiLoader({
    googleMapsApiKey: process.env.REACT_APP_GOOGLE_MAPS_API_KEY,
  });

  const handleMarkerClick = useCallback((location) => {
    setSelected(location);
  }, []);

  const handleMapClick = useCallback(() => {
    setSelected(null);
  }, []);

  if (loadError) {
    return <div className="page">Failed to load Google Maps: {loadError.message}</div>;
  }

  if (!isLoaded) {
    return <div className="page">Loading map…</div>;
  }

  return (
    <GoogleMap
      mapContainerStyle={MAP_STYLE}
      center={CENTER}
      zoom={11}
      onClick={handleMapClick}
    >
      {MOCK_LOCATIONS.map((loc) => (
        <Marker
          key={loc.id}
          position={{ lat: loc.lat, lng: loc.lng }}
          onClick={() => handleMarkerClick(loc)}
        />
      ))}

      {selected && (
        <InfoWindow
          position={{ lat: selected.lat, lng: selected.lng }}
          onCloseClick={() => setSelected(null)}
        >
          <div style={{ minWidth: 140 }}>
            <strong>{selected.name}</strong>
            <p style={{ margin: '4px 0 0' }}>Quantity: {selected.quantity}</p>
          </div>
        </InfoWindow>
      )}
    </GoogleMap>
  );
}
